script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', null, 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  f.getItem('d32')._controlBehavior.add_onRender(on$Voucher$GridDetailRender);
  f.getItem('r30')._controlBehavior.add_onRender(on$Voucher$GridTaxRender);
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  try {f.getItem('r30')._controlBehavior.remove_onRender(on$Voucher$GridTaxRender);} catch (ex) {}
  try {f.getItem('d32')._controlBehavior.remove_onRender(on$Voucher$GridDetailRender);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}

function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d32')._controlBehavior, z = f.getItem('r30')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      z.setSequenceNumber('line_nbr');
      z.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$Voucher$GridDetailRender(sender, eventArgs) {onChange$Voucher$TransactionType(eventArgs.grid.get_element().parentForm.getItem('loai_ct'));}
function on$Voucher$GridTaxRender(sender, eventArgs) {
  var z = eventArgs.grid.get_element().parentForm.getItem("r30")._controlBehavior;
  z._setColumnVisible(z._getColumnOrder('ma_tt'), false);
}
/* </flatten> */
      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d32')._controlBehavior, z = f.getItem('r30')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt,t_thue_nt,t_tt_nt:t_tien,t_thue,t_tt');
    v.addGridFields(g, 'tien_nt, thue_nt, tt_nt:tien, thue, tt');
    v.addGridFields(z, 't_tien_nt,t_thue_nt:t_tien,t_thue');
    &ScriptTaxGridDetailCurrencyTotalFields;

    v.set_referenceFields(null);
    &ScriptTaxGridDetailCurrencyExpression;
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d32', 'ma_tt'], ['r30', 'ma_tt']&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}

function onChange$Voucher$Tab(sender, e) { sender.parentForm.focusWhenTabChanged(['d32', 'r30'&ListTabChange;&PostTabChange;]);&PostTabFocus;}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$TransactionType(o) {
  var g = o.parentForm.getItem("d32")._controlBehavior;
  var v = ($func.trim(o.value) == '3');
  g._setColumnVisible(g._getColumnOrder('ma_kh_i'), v);
  g._setColumnVisible(g._getColumnOrder('ten_kh_i%l'), v);
}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem("d32")._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
    g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ong_ba', result[2].Value, null, true);
      f.live(f.getItem('ong_ba'));
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}

